from functools import lru_cache
from pathlib import Path
from babel.support import Translations

LOCALES_DIR = Path(__file__).parent / "locales"
SUPPORTED_LOCALES = ["en", "uk", "de", "fr"]
DEFAULT_LOCALE = "en"

@lru_cache(maxsize=None)
def get_translations(locale: str) -> Translations:
    try:
        return Translations.load(LOCALES_DIR, [locale])
    except FileNotFoundError:
        return Translations.load(LOCALES_DIR, [DEFAULT_LOCALE])

def gettext(message: str, locale: str = DEFAULT_LOCALE) -> str:
    return get_translations(locale).gettext(message)

def ngettext(singular: str, plural: str, n: int, locale: str = DEFAULT_LOCALE) -> str:
    return get_translations(locale).ngettext(singular, plural, n)

class Product(Base):
    id = Column(String, primary_key=True)
    translations = relationship("ProductTranslation", back_populates="product")

    def _get_translation(self, locale: str, field: str) -> str:
        for t in self.translations:
            if t.locale == locale:
                return getattr(t, field)
        base = locale.split("-")[0]
        for t in self.translations:
            if t.locale == base:
                return getattr(t, field)
        for t in self.translations:
            if t.locale == DEFAULT_LOCALE:
                return getattr(t, field)
        return ""
